def daily_temperatures(temps):
    n      = len(temps)
    result = [0] * n
    stack  = []  # indices of days waiting for a warmer day
    for i, t in enumerate(temps):
        while stack and temps[stack[-1]] < t:
            j          = stack.pop()
            result[j]  = ___________  # days between j and i
        stack.append(i)
    return result
